    [Fact]
    public void WFiltro_VistoHasValidValue_ShouldAddParameterAndWhereClause()
    {
        // Arrange
        var VistoValue = 1;
        var filtro = new FilterProDespesas
        {
            Visto = VistoValue,
            LogicalOperator = " AND "
        };
        // Act
        var result = _serviceS.WFiltroProDespesas(filtro);
        // Assert
        result.Should().NotBeNull();
        // Check parameter
        var VistoParameter = result.Value.parametros.FirstOrDefault(p => p.ParameterName == $"@{DBProDespesasDicInfo.Visto}");
