        VistoParameter.Value.Should().Be(VistoValue);
        // Check where clause
        result.Value.where.Should().Contain($"[{DBProDespesasDicInfo.PTabelaNome}].[{DBProDespesasDicInfo.Visto}] = @{DBProDespesasDicInfo.Visto}");
    }

